+    #[test]
+    fn edge_logging_disabled() {
+        let mut config = test_config();
+        config.enable_logging = false;
+        let monitor = ResizeSlaMonitor::new(config);
+
+        for i in 0..10 {
+            monitor.process_latency(10.0 + i as f64, (80, 24), false);
